INSERT INTO risk_actuarial_ho_code (category, sub_category, parent_group_description, category_description, sub_category_description, risk_actuarial_ho_code_category_id, created_date)
VALUES (61, 30, 'Fraud forgery', 'Other Forgery etc.', 'In the course of a trade or business: (a) applying to an unhallmarked article a description indicating that it is wholly or partly made of gold, silver or platinum, or (b) supplying or offering to supply an unhallmarked article to which such a description is applied, or (c) without authority striking an article with a mark purporting to be a sponsor''s mark authorised under this section, or (d) false statement in furnishing information to an assay office for purposes of sub-section (2) (Article made in UK etc), or (e) making an addition, alteration or repair to an article bearing approved hallmarks, without written consent of any assay office, or (f) removing, altering or effacing any mark struck on an article, without written consent of an assay office, or (g) knowingly supplying etc. any article bearing any mark of the character of a hallmark and which under sub-section (1) of this section may, if the article is in the possession of an assay office, be cancelled, obliterated or defaced etc', (SELECT id FROM risk_actuarial_ho_code_category WHERE category_name = 'FRAUD_AND_FORGERY'), CURRENT_TIMESTAMP);

